{"type": "email", "id": "email_003", "subject": "Customer Satisfaction Survey Results", "from": "sarah.jones@mediconn.com", "from_name": "Sarah Jones", "to": ["emily.patel@mediconn.com"], "cc": [], "date": "2022-09-23 16:00:00", "body": "Hi Emily, 

